const items = $input.all();

if (!items || items.length === 0) {
  throw new Error('The sub-workflow received no input item.');
}

const unit = items[0].json || {};

for (const field of ['username', 'topic', 'prompt_name', 'prompt']) {
  const value = unit[field];
  if (typeof value !== 'string' || !value.trim()) {
    throw new Error(`Missing or invalid unit-of-work field: ${field}`);
  }
}

function sanitize(value) {
  let result = String(value).normalize('NFKC').trim();
  result = result.replace(/[\\/]+/g, '-');
  result = result.split('').filter(c => c.charCodeAt(0) >= 32 && c.charCodeAt(0) !== 127).join('');
  result = result.replace(/\s+/g, '_');
  result = result.replace(/[^a-zA-Z0-9._-]/g, '-');
  result = result.replace(/-+/g, '-');
  result = result.replace(/^[\-_.]+|[\-_.]+$/g, '');
  return result || 'unnamed';
}

const now = new Date();
const currentDate = now.toISOString().slice(0, 10);

const usernameKey = sanitize(unit.username);
const topicKey = sanitize(unit.topic);
const promptNameKey = sanitize(unit.prompt_name);

return [{
  json: {
    user_id: unit.user_id,
    username: unit.username,
    email: unit.email,
    topic: unit.topic,
    prompt_name: unit.prompt_name,
    prompt: unit.prompt,
    date: currentDate,
    path1: `${usernameKey}/by-topic/${topicKey}/${promptNameKey}/${currentDate}.html`,
    path2: `${usernameKey}/by-date/${currentDate}/${topicKey}/${promptNameKey}.html`
  }
}];

const items = $input.all();

if (!items || items.length === 0) {
  throw new Error('LiteLLM returned no input item.');
}

const api = items[0].json || {};
const unitItems = $('Prepare Unit of Work').all();

if (!unitItems || unitItems.length === 0) {
  throw new Error('Prepare Unit of Work returned no item.');
}

const unit = unitItems[0].json || {};
const choices = api.choices || [];

if (choices.length === 0) {
  throw new Error(`LiteLLM returned no choices: ${JSON.stringify(api)}`);
}

const message = choices[0].message || {};
let response = message.content;

if (typeof response !== 'string' || !response) {
  throw new Error(`LiteLLM returned no message content: ${JSON.stringify(api)}`);
}

// ── Citation enrichment ──────────────────────────────────────────────────────
const annotations = Array.isArray(message.annotations) ? message.annotations : [];

const citations = annotations
  .filter(ann => ann.type === 'url_citation' && ann.url_citation)
  .map(ann => ann.url_citation)
  .filter(c => typeof c.url === 'string' && c.url.trim());

if (citations.length > 0) {
  // Deduplicate by URL
  const seen = new Set();
  const unique = citations.filter(c => {
    if (seen.has(c.url)) return false;
    seen.add(c.url);
    return true;
  });

  const refLines = unique.map((c, i) => {
    const label = (c.title || c.url).replace(/[[]]/g, '');
    return `${i + 1}. [${label}](${c.url})`;
  });

  response = response.trimEnd() + '\n\n---\n\n**Sources**\n\n' + refLines.join('\n');
}
// ── End citation enrichment ──────────────────────────────────────────────────

const result = Object.assign({}, unit);
result.response = response;
result.citations = citations.map(({ url, title }) => ({ url, title }));

return [{ json: result }];

const items = $input.all();

if (!items || items.length === 0) {
  throw new Error('Markdown node returned no input item.');
}

const rendered = items[0].json || {};
const unitItems = $('Extract Response').all();

if (!unitItems || unitItems.length === 0) {
  throw new Error('Extract Response returned no item.');
}

const unit = unitItems[0].json || {};

let html = rendered.data;

if (html === undefined || html === null) {
  html = rendered.html;
}

if (html === undefined || html === null) {
  html = rendered.response;
}

if (typeof html !== 'string') {
  throw new Error(`Markdown node returned no HTML string: ${JSON.stringify(rendered)}`);
}

const result = Object.assign({}, unit);
result.html = html;

return [{ json: result }];

const unitItems = $('Prepare Uploads').all();

if (!unitItems || unitItems.length === 0) {
  throw new Error('Prepare Uploads returned no item.');
}

const unit = unitItems[0].json || {};

return [{
  json: {
    success: true,
    user_id: unit.user_id,
    username: unit.username,
    topic: unit.topic,
    prompt_name: unit.prompt_name,
    date: unit.date,
    uploaded_keys: [
      unit.path1,
      unit.path2
    ]
  }
}];
